\ifthenelse{\boolean{main}}{
  \exa[CH]{EEE} % \cite{book}
}{
  % \exa{}
}
\question{
Una distancia de $3.5\,\text{km}$ se expresa en metros dentro del Sistema Internacional.  
¿Cuál es su valor en metros?

\begin{enumerate}
\item $3.5\times10^{2}\,\text{m}$
\item $3.5\times10^{3}\,\text{m}$\rightoption
\item $3.5\times10^{4}\,\text{m}$
\item $3.5\times10^{5}\,\text{m}$
\item $3.5\times10^{6}\,\text{m}$
\end{enumerate}
}{
  \paragraph{Solución}
  \begin{gather*}
    \ell = \SI{3.5}{km} \times \frac{\SI{1000}{m}}{\SI{1}{km}} \\
    \ell = \SI{3500}{m} \\
    \ell = \SI{3.5e+3}{m} \\
  \end{gather*}
}

