}
\question{
Dos vectores $\vec{A}$ y $\vec{B}$ tienen magnitudes
$\abs{\vec{A}} = \SI{6}{m}$ y $\abs{\vec{B}} = \SI{8}{m}$.
Si $\vec{A}$ apunta en la dirección $+x$ y $\vec{B}$ apunta en la dirección $+y$,
¿cuál es la magnitud y dirección (respecto al eje $+x$) del vector resultante
$\vec{R} = \vec{A} + \vec{B}$?
\pts[add]{3}
\begin{enumerate}
\item $\SI{10}{m}$, $\ang{37}$
\item $\SI{10}{m}$, $\ang{53}$\rightoption
\item $\SI{14}{m}$, $\ang{45}$
\item $\SI{10}{m}$, $\ang{45}$
\item $\SI{14}{m}$, $\ang{53}$
\end{enumerate}
}{
  \paragraph{Solución}
  \begin{gather*}
    R = \sqrt{A^2 + B^2} = \sqrt{6^2 + 8^2}
      = \sqrt{36 + 64} = \sqrt{100} = \SI{10}{m} \\
    \theta = \arctan\!\left(\frac{B}{A}\right)
           = \arctan\!\left(\frac{8}{6}\right)
           = \arctan(1.33) \approx \ang{53}
  \end{gather*}
}

