\question{
Dos fuerzas actúan sobre una barra que puede girar respecto a un punto fijo.
La fuerza $F_1 = \SI{20}{N}$ se aplica perpendicularmente a $\SI{0.6}{m}$
del pivote, y la fuerza $F_2 = \SI{30}{N}$ se aplica a $\SI{0.3}{m}$ del
pivote formando un ángulo de $\ang{90}$ con la barra.
¿Cuál es el torque neto respecto al pivote si ambas fuerzas generan rotación
en sentidos opuestos?
\pts[add]{3}
\begin{enumerate}
\item $\SI{0}{N.m}$
\item $\SI{3}{N.m}$\rightoption
\item $\SI{6}{N.m}$
\item $\SI{12}{N.m}$
\item $\SI{21}{N.m}$
\end{enumerate}
}{
  \paragraph{Solución}
  \begin{gather*}
    \tau_1 = F_1 \cdot r_1 \cdot \sin(\ang{90})
           = (\SI{20}{N})(\SI{0.6}{m})(1)
           = \SI{12}{N.m} \\
    \tau_2 = F_2 \cdot r_2 \cdot \sin(\ang{90})
           = (\SI{30}{N})(\SI{0.3}{m})(1)
           = \SI{9}{N.m} \\
    \tau_{\text{neto}} = \tau_1 - \tau_2
                       = 12 - 9
                       = \SI{3}{N.m}
  \end{gather*}
}

\ifthenelse{\boolean{main}}{
  \exa[CH]{EEE} % \cite{book}
}{
  % \exa{}
}
\question{
Un automóvil parte del reposo y acelera uniformemente a $\SI{4}{\ace}$
durante $\SI{5}{s}$; luego mantiene velocidad constante durante $\SI{10}{s}$.
¿Cuál es la distancia total recorrida?
\pts[add]{3}
\begin{enumerate}
\item $\SI{150}{m}$
\item $\SI{200}{m}$
\item $\SI{250}{m}$\rightoption
\item $\SI{300}{m}$
\item $\SI{350}{m}$
\end{enumerate}
}{
  \paragraph{Solución}
  Fase 1 (MRUA):
  \begin{gather*}
    v_f = v_0 + at = 0 + (4)(5) = \SI{20}{m/s} \\
    d_1 = v_0 t + \tfrac{1}{2}at^2 = 0 + \tfrac{1}{2}(4)(5)^2 = \SI{50}{m}
  \end{gather*}
  Fase 2 (MRU):
  \begin{gather*}
    d_2 = v_f \cdot t = (20)(10) = \SI{200}{m}
  \end{gather*}
  Total:
  \begin{gather*}
    d = d_1 + d_2 = 50 + 200 = \SI{250}{m}
  \end{gather*}
}

