\question{
Un automóvil parte del reposo y acelera uniformemente a $\SI{4}{\ace}$
durante $\SI{5}{s}$; luego mantiene velocidad constante durante $\SI{10}{s}$.
¿Cuál es la distancia total recorrida?
\pts[add]{3}
\begin{enumerate}
\item $\SI{150}{m}$
\item $\SI{200}{m}$
\item $\SI{250}{m}$\rightoption
\item $\SI{300}{m}$
\item $\SI{350}{m}$
\end{enumerate}
}{
  \paragraph{Solución}
  Fase 1 (MRUA):
  \begin{gather*}
    v_f = v_0 + at = 0 + (4)(5) = \SI{20}{m/s} \\
    d_1 = v_0 t + \tfrac{1}{2}at^2 = 0 + \tfrac{1}{2}(4)(5)^2 = \SI{50}{m}
  \end{gather*}
  Fase 2 (MRU):
  \begin{gather*}
    d_2 = v_f \cdot t = (20)(10) = \SI{200}{m}
  \end{gather*}
  Total:
  \begin{gather*}
    d = d_1 + d_2 = 50 + 200 = \SI{250}{m}
  \end{gather*}
}

\ifthenelse{\boolean{main}}{
  \exa[CH]{EEE} % \cite{book}
}{
  % \exa{}
}
\question{
Un bloque de $\SI{4}{kg}$ se desliza sobre una superficie horizontal con
coeficiente de fricción cinética $\mu_k = 0.25$. Se aplica una fuerza
horizontal de $\SI{30}{N}$. ¿Cuál es la aceleración del bloque?
Use $g = \SI{10}{\ace}$.
\pts[add]{3}
\begin{enumerate}
\item $\SI{2.5}{\ace}$
\item $\SI{3.0}{\ace}$
\item $\SI{5.0}{\ace}$\rightoption
\item $\SI{7.5}{\ace}$
\item $\SI{10.0}{\ace}$
\end{enumerate}
}{
  \paragraph{Solución}
  \begin{gather*}
    N = mg = (4)(10) = \SI{40}{N} \\
    f_k = \mu_k N = (0.25)(40) = \SI{10}{N} \\
    F_{\text{neta}} = F - f_k = 30 - 10 = \SI{20}{N} \\
    a = \frac{F_{\text{neta}}}{m} = \frac{20}{4} = \SI{5.0}{\ace}
  \end{gather*}
}

